#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int S = (2<<9)+5;
LL n,k,dp[15][105][S],Sum;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    n=read(),k=read(),dp[0][0][0]=1;
    for(int i=1;i<=n;i++)
        for(int j=0;j<=min((i-1)*n,k);j++)
        for(int lst=0;lst<(1<<n);lst++){
            if(!dp[i-1][j][lst])continue;
            for(int now=0;now<(1<<n);now++){
                if((now&(now>>1))||(now&(now<<1)))continue;
                if((now&lst)||(now&(lst<<1))||(now&(lst>>1)))continue;
                int cnt=0,tmp=now;
                while(tmp)cnt+=tmp%2,tmp/=2;
                dp[i][j+cnt][now]+=dp[i-1][j][lst];
            }
        }
    for(int now=0;now<(1<<n);now++)Sum+=dp[n][k][now];
    cout<<Sum<<"\n";
    return 0;
}
